function candidate(sourceMapData, sourceMapUrl) {
  const parsedMap = typeof sourceMapData === "string" ? JSON.parse(sourceMapData) : sourceMapData;
  const consumer = "sections" in parsedMap
    ? new IndexedSourceMapConsumer(parsedMap, sourceMapUrl)
    : new BasicSourceMapConsumer(parsedMap, sourceMapUrl);

  return Promise.resolve(consumer);
}
